import Layout from './components/Layout';

function App() {
  return (
    <div className="App-main">
      <header>
        <ul>
          <li><a href="https://github.com/ChaerinYu">About Me</a></li>
          <li><a href="https://github.com/ChaerinYu">Experience</a></li>
          <li><a href="https://github.com/ChaerinYu">Projects</a></li>
          <li><a href="https://github.com/ChaerinYu">Skills</a></li>
          <li><a href="https://github.com/ChaerinYu">Photo</a></li>
        </ul>
      </header>

      <div className="App-layout">
        <div className="App-contents">
          <Layout />
        </div>
        <div className="App-footer"></div>
      </div>
    </div>
  );
}

export default App;
